package com.example.datatransfer;

import io.grpc.ManagedChannel;
import io.grpc.ManagedChannelBuilder;
import io.grpc.stub.StreamObserver;

import java.io.InputStream;
import java.nio.file.Files;
import java.nio.file.Path;
import java.util.Map;
import java.util.UUID;
import java.util.concurrent.CountDownLatch;
import java.util.concurrent.TimeUnit;

public class DataTransferClient {
    private final ManagedChannel channel;
    private final DataTransferServiceGrpc.DataTransferServiceStub asyncStub;
    private final DataTransferServiceGrpc.DataTransferServiceBlockingStub blockingStub;

    public DataTransferClient(String host, int port) {
        this.channel = ManagedChannelBuilder.forAddress(host, port)
                .usePlaintext()
                .maxInboundMessageSize(Integer.MAX_VALUE)
                .build();
        this.asyncStub = DataTransferServiceGrpc.newStub(channel);
        this.blockingStub = DataTransferServiceGrpc.newBlockingStub(channel);
    }

    public UploadResponse uploadFile(Path filePath, Map<String, String> attributes) throws Exception {
        CountDownLatch latch = new CountDownLatch(1);
        UploadResponse[] result = new UploadResponse[1];
        Throwable[] error = new Throwable[1];

        StreamObserver<UploadResponse> responseObserver = new StreamObserver<>() {
            @Override
            public void onNext(UploadResponse value) {
                result[0] = value;
            }

            @Override
            public void onError(Throwable t) {
                error[0] = t;
                latch.countDown();
            }

            @Override
            public void onCompleted() {
                latch.countDown();
            }
        };

        StreamObserver<UploadRequest> requestObserver = asyncStub.upload(responseObserver);

        UploadMetadata metadata = UploadMetadata.newBuilder()
                .setFileName(filePath.getFileName().toString())
                .setContentType(Files.probeContentType(filePath) == null ? "application/octet-stream" : Files.probeContentType(filePath))
                .putAllAttributes(attributes)
                .build();

        requestObserver.onNext(UploadRequest.newBuilder().setMetadata(metadata).build());

        byte[] buffer = new byte[1024 * 1024];
        try (InputStream inputStream = Files.newInputStream(filePath)) {
            int read;
            while ((read = inputStream.read(buffer)) != -1) {
                requestObserver.onNext(
                        UploadRequest.newBuilder()
                                .setChunk(com.google.protobuf.ByteString.copyFrom(buffer, 0, read))
                                .build()
                );
            }
        }

        requestObserver.onCompleted();

        if (!latch.await(5, TimeUnit.MINUTES)) {
            throw new RuntimeException("Upload timed out");
        }
        if (error[0] != null) {
            throw new RuntimeException(error[0]);
        }
        return result[0];
    }

    public void downloadFile(String remoteFileName, Path destination) throws Exception {
        Files.createDirectories(destination.getParent() == null ? Path.of(".") : destination.getParent());
        try (var outputStream = Files.newOutputStream(destination)) {
            for (DownloadChunk chunk : blockingStub.download(DownloadRequest.newBuilder().setFileName(remoteFileName).build())) {
                chunk.getChunk().writeTo(outputStream);
            }
        }
    }

    public void bidirectionalTransfer(int messageCount) throws Exception {
        CountDownLatch latch = new CountDownLatch(1);

        StreamObserver<TransferMessage> responseObserver = new StreamObserver<>() {
            @Override
            public void onNext(TransferMessage value) {
                System.out.println("Received response: " + value.getCorrelationId() + ", bytes=" + value.getPayload().size());
            }

            @Override
            public void onError(Throwable t) {
                t.printStackTrace();
                latch.countDown();
            }

            @Override
            public void onCompleted() {
                latch.countDown();
            }
        };

        StreamObserver<TransferMessage> requestObserver = asyncStub.transfer(responseObserver);

        for (int i = 0; i < messageCount; i++) {
            byte[] payload = new byte[1024 * 1024];
            TransferMessage message = TransferMessage.newBuilder()
                    .setCorrelationId(UUID.randomUUID().toString())
                    .setPayload(com.google.protobuf.ByteString.copyFrom(payload))
                    .putHeaders("sequence", String.valueOf(i))
                    .putHeaders("type", "data")
                    .build();
            requestObserver.onNext(message);
        }

        requestObserver.onCompleted();

        if (!latch.await(5, TimeUnit.MINUTES)) {
            throw new RuntimeException("Transfer timed out");
        }
    }

    public void shutdown() throws InterruptedException {
        channel.shutdown().awaitTermination(30, TimeUnit.SECONDS);
    }
}